const prop = $('Set Report Config (Weekly)').first().json.prop;
// ============================================
// PROCESS ALL DATA - COM 3 MESES ANTERIORES
// ============================================

const currentMonthRaw = $('Get Current Month Data').all();
const categoriasRaw = $('Get Categorias').all();
const contasRaw = $('Get Contas').all();
const month1Raw = $('Get Month -1').all();
const month2Raw = $('Get Month -2').all();
const month3Raw = $('Get Month -3').all();

// === MAPEAR CATEGORIAS E CONTAS ===
const categoriasMap = {};
categoriasRaw.forEach(item => {
  const props = item.json?.properties || {};
  const id = item.json?.id;
  let nome = '';
  for (const [key, value] of Object.entries(props)) {
    if (value.type === 'title' && value.title?.length > 0) {
      nome = value.title[0]?.plain_text || '';
      break;
    }
  }
  if (id && nome) categoriasMap[id] = nome;
});

const contasMap = {};
contasRaw.forEach(item => {
  const props = item.json?.properties || {};
  const id = item.json?.id;
  let nome = '';
  for (const [key, value] of Object.entries(props)) {
    if (value.type === 'title' && value.title?.length > 0) {
      nome = value.title[0]?.plain_text || '';
      break;
    }
  }
  if (id && nome) contasMap[id] = nome;
});

const formasPagamentoMap = {};

// Fuso horário São Paulo
const agora = new Date();
const hojeStr = agora.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' });
const hoje = new Date(hojeStr);
const diaDoMes = hoje.getDate();
const seteDiasAtras = new Date(hoje);
seteDiasAtras.setDate(hoje.getDate() - 7);

// Nomes dos meses
const nomesMeses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
const mesAtual = hoje.getMonth();

// Calcular dias de cada mês
const getDiasMes = (ano, mes) => new Date(ano, mes + 1, 0).getDate();
const diasMes0 = getDiasMes(hoje.getFullYear(), mesAtual);
const diasMes1 = getDiasMes(hoje.getFullYear(), mesAtual - 1);
const diasMes2 = getDiasMes(hoje.getFullYear(), mesAtual - 2);
const diasMes3 = getDiasMes(hoje.getFullYear(), mesAtual - 3);
const maxDias = Math.max(diasMes0, diasMes1, diasMes2, diasMes3);

// Função para processar despesas
const processExpenses = (raw) => raw.map(item => {
  const p = item.json?.properties ?? {};
  return { data: p['Data']?.date?.start ?? null, valor: p['Valor']?.number ?? 0 };
}).filter(e => e.data);

// Função para calcular acumulado por dia
const calcularAcumulado = (expenses, diasMes) => {
  const acumulado = {};
  let acum = 0;
  expenses.sort((a, b) => a.data.localeCompare(b.data)).forEach(e => {
    const dia = parseInt(e.data.split('-')[2]);
    acum += e.valor;
    acumulado[dia] = acum;
  });
  // Preencher dias vazios
  for (let d = 1; d <= diasMes; d++) {
    if (!acumulado[d]) acumulado[d] = d > 1 ? (acumulado[d-1] || 0) : 0;
  }
  return acumulado;
};

// === PROCESSAR MÊS ATUAL (com categorias para resumo semanal) ===
const expensesCurrentMonth = currentMonthRaw.map(item => {
  const p = item.json?.properties ?? {};
  const catRelation = p[prop.categoria]?.relation || [];
  const categoriaId = catRelation[0]?.id || null;
  const categoria = categoriaId ? (categoriasMap[categoriaId] || 'Sem categoria') : 'Sem categoria';
  const contaRelation = p['Conta']?.relation || [];
  const contaId = contaRelation[0]?.id || null;
  const conta = contaId ? (contasMap[contaId] || 'Sem conta') : 'Sem conta';
  return {
    id: p['ID_transacao']?.unique_id?.number ?? 'N/A',
    despesa: p[prop.title]?.title?.[0]?.text?.content ?? p[prop.title]?.title?.[0]?.plain_text ?? 'Sem título',
    data: p['Data']?.date?.start ?? null,
    valor: p['Valor']?.number ?? 0,
    categoria, conta,
    formaPagamento: (() => { const rel = p[prop.forma_pagamento]?.relation || []; const fpId = rel[0]?.id; return fpId ? (formasPagamentoMap[fpId] || 'N/A') : 'N/A'; })()
  };
}).filter(e => e.data);

// Filtrar semana
const expensesSemana = expensesCurrentMonth.filter(e => {
  const dataExp = new Date(e.data + 'T12:00:00');
  return dataExp >= seteDiasAtras && dataExp <= hoje;
});

// === CALCULAR ACUMULADOS ===
const acumMes0 = calcularAcumulado(expensesCurrentMonth.map(e => ({ data: e.data, valor: e.valor })), diasMes0);
const acumMes1 = calcularAcumulado(processExpenses(month1Raw), diasMes1);
const acumMes2 = calcularAcumulado(processExpenses(month2Raw), diasMes2);
const acumMes3 = calcularAcumulado(processExpenses(month3Raw), diasMes3);

// Totais para comparação
const totalMes0 = acumMes0[diaDoMes] || 0;
const totalMes1AteDia = acumMes1[diaDoMes] || 0;
const totalMes1Completo = acumMes1[diasMes1] || 0;

// === TOTAIS SEMANA ===
const totalSemana = expensesSemana.reduce((sum, e) => sum + e.valor, 0);
const qtdSemana = expensesSemana.length;

const porConta = {};
expensesSemana.forEach(e => {
  if (!porConta[e.conta]) porConta[e.conta] = { total: 0, count: 0 };
  porConta[e.conta].total += e.valor;
  porConta[e.conta].count++;
});

const porCategoria = {};
expensesSemana.forEach(e => {
  if (!porCategoria[e.categoria]) porCategoria[e.categoria] = { total: 0, count: 0 };
  porCategoria[e.categoria].total += e.valor;
  porCategoria[e.categoria].count++;
});

const porPagamento = {};
expensesSemana.forEach(e => {
  if (!porPagamento[e.formaPagamento]) porPagamento[e.formaPagamento] = { total: 0, count: 0 };
  porPagamento[e.formaPagamento].total += e.valor;
  porPagamento[e.formaPagamento].count++;
});

// === ORÇAMENTO POR CATEGORIA ===
const categoryBudget = {};
let totalOrcamento = 0;
let totalDespesasMes = 0;

categoriasRaw.forEach(item => {
  const props = item.json?.properties || {};
  let nome = '';
    for (const [key, value] of Object.entries(props)) {
      if (value.type === 'title' && value.title?.length > 0) {
        nome = value.title[0]?.plain_text || '';
        break;
      }
    }
    if (!nome) nome = 'Sem nome';
  const despesasEsteMes = props[prop.este_mes]?.rollup?.number ?? 0;
  const orcamentoMensal = props[prop.orcamento]?.number ?? 0;
  const usoPercent = props[prop.uso]?.formula?.number ?? 0;
  categoryBudget[nome] = { despesasEsteMes, orcamentoMensal, usoPercent };
  totalDespesasMes += despesasEsteMes;
  totalOrcamento += orcamentoMensal;
});

const fmtDate = (d) => `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}`;
const periodoLabel = `${fmtDate(seteDiasAtras)} a ${fmtDate(hoje)}`;

// === ARRAYS PARA GRÁFICO - 4 LINHAS ===
const diasLabels = [];
const valoresMes0 = [];
const valoresMes1 = [];
const valoresMes2 = [];
const valoresMes3 = [];

for (let d = 1; d <= maxDias; d++) {
  diasLabels.push(d.toString());
  // Mês atual: só até hoje
  valoresMes0.push(d <= diaDoMes ? (acumMes0[d] || 0) : null);
  // Meses anteriores: completos
  valoresMes1.push(d <= diasMes1 ? (acumMes1[d] || 0) : null);
  valoresMes2.push(d <= diasMes2 ? (acumMes2[d] || 0) : null);
  valoresMes3.push(d <= diasMes3 ? (acumMes3[d] || 0) : null);
}

// Labels dos meses
const getMesLabel = (offset) => {
  let m = mesAtual - offset;
  if (m < 0) m += 12;
  return nomesMeses[m];
};

return [{
  json: {
    periodo: periodoLabel,
    diaDoMes,
    maxDias,
    mesesLabels: {
      mes0: getMesLabel(0),
      mes1: getMesLabel(1),
      mes2: getMesLabel(2),
      mes3: getMesLabel(3)
    },
    totais: { 
      semana: totalSemana, 
      qtdSemana, 
      mesAtual: totalMes0, 
      mesAnteriorAteDia: totalMes1AteDia,
      mesAnteriorCompleto: totalMes1Completo
    },
    por_conta: porConta,
    por_categoria: porCategoria,
    por_pagamento: porPagamento,
    categoryBudget,
    totalOrcamento,
    totalDespesasMes,
    grafico: {
      labels: diasLabels,
      mes0: valoresMes0,
      mes1: valoresMes1,
      mes2: valoresMes2,
      mes3: valoresMes3
    }
  }
}];

// ============================================
// PREPARE COMPARISON CHART - 4 MESES
// Mês atual + 3 meses anteriores
// ============================================

const data = $('Format Weekly Summary').first().json;
const grafico = data.grafico;
const labels = data.mesesLabels;

const chartConfig = {
  type: 'line',
  data: {
    labels: grafico.labels,
    datasets: [
      {
        label: `${labels.mes0} (atual)`,
        data: grafico.mes0,
        borderColor: '#4CAF50',
        backgroundColor: 'rgba(76, 175, 80, 0.15)',
        borderWidth: 3,
        fill: true,
        tension: 0.2,
        pointRadius: 3,
        pointBackgroundColor: '#4CAF50',
        spanGaps: false
      },
      {
        label: labels.mes1,
        data: grafico.mes1,
        borderColor: '#9E9E9E',
        backgroundColor: 'rgba(158, 158, 158, 0.05)',
        borderWidth: 2,
        borderDash: [6, 4],
        fill: false,
        tension: 0.2,
        pointRadius: 1,
        spanGaps: false
      },
      {
        label: labels.mes2,
        data: grafico.mes2,
        borderColor: '#2196F3',
        backgroundColor: 'rgba(33, 150, 243, 0.05)',
        borderWidth: 2,
        borderDash: [3, 3],
        fill: false,
        tension: 0.2,
        pointRadius: 1,
        spanGaps: false
      },
      {
        label: labels.mes3,
        data: grafico.mes3,
        borderColor: '#FF9800',
        backgroundColor: 'rgba(255, 152, 0, 0.05)',
        borderWidth: 2,
        borderDash: [2, 2],
        fill: false,
        tension: 0.2,
        pointRadius: 1,
        spanGaps: false
      }
    ]
  },
  options: {
    responsive: true,
    plugins: {
      title: {
        display: true,
        text: 'Comparação Gastos Acumulados - Últimos 4 Meses',
        font: { size: 14, weight: 'bold' }
      },
      legend: {
        position: 'top',
        labels: { usePointStyle: true, padding: 10, font: { size: 10 } }
      }
    },
    scales: {
      y: {
        beginAtZero: true,
        grid: { color: 'rgba(0,0,0,0.05)' },
        title: { display: true, text: 'Acumulado (R$)', font: { size: 10 } }
      },
      x: {
        grid: { display: false },
        title: { display: true, text: 'Dia do Mês', font: { size: 10 } }
      }
    }
  }
};

const chartJson = encodeURIComponent(JSON.stringify(chartConfig));
const chartUrl = `https://quickchart.io/chart?c=${chartJson}&w=750&h=420&bkg=white`;

return [{ json: { chartUrl, chartConfig } }];

// ============================================
// FORMAT WEEKLY SUMMARY
// ============================================

const data = $json;
const _brand = $('Set Report Config (Weekly)').first().json.brand_name;

const fmtBRL = (n) => `R$ ${Math.round(Number(n || 0)).toLocaleString('pt-BR')}`;
const fmtPct = (n) => `${Number(n || 0).toFixed(0)}%`;

const mesAtualLabel = data.mesesLabels.mes0;
const mesAnteriorLabel = data.mesesLabels.mes1;

const lines = [
  '🏺 *' + _brand + '* 🏺',
  '',
  '📊 *RELATÓRIO SEMANAL DE DESPESAS*',
  '════════════════════════════',
  '',
  `📅 *Período:* ${data.periodo}`,
  '',
  '💰 *RESUMO FINANCEIRO*',
  `   Total Geral: ${fmtBRL(data.totais.semana)}`,
  `   Transações: ${data.totais.qtdSemana}`,
  ''
];

if (Object.keys(data.por_conta).length > 0) {
  lines.push('🏦 *POR CONTA*');
  Object.entries(data.por_conta)
    .sort((a, b) => b[1].total - a[1].total)
    .forEach(([conta, info]) => {
      const pct = data.totais.semana > 0 ? (info.total / data.totais.semana * 100) : 0;
      lines.push(`   • ${conta}: ${fmtBRL(info.total)} (${fmtPct(pct)})`);
    });
  lines.push('');
}

if (Object.keys(data.por_categoria).length > 0) {
  lines.push('🗂️ *POR CATEGORIA*');
  Object.entries(data.por_categoria)
    .sort((a, b) => b[1].total - a[1].total)
    .forEach(([cat, info]) => {
      const pct = data.totais.semana > 0 ? (info.total / data.totais.semana * 100) : 0;
      lines.push(`   • ${cat}: ${fmtBRL(info.total)} (${fmtPct(pct)}) - ${info.count} ${info.count === 1 ? 'item' : 'itens'}`);
    });
  lines.push('');
}

if (Object.keys(data.por_pagamento).length > 0) {
  lines.push('💳 *POR FORMA DE PAGAMENTO*');
  Object.entries(data.por_pagamento)
    .sort((a, b) => b[1].total - a[1].total)
    .forEach(([method, info]) => {
      lines.push(`   • ${method}: ${fmtBRL(info.total)} - ${info.count} ${info.count === 1 ? 'item' : 'itens'}`);
    });
}

lines.push('');
lines.push('━━━━━━━━━━━━━━━━━━━━━');
lines.push('');
  lines.push('📈 *GASTO ACUMULADO NO MÊS vs ORÇAMENTO*');
lines.push('');

const categoriasOrd = Object.entries(data.categoryBudget)
  .filter(([, d]) => d.orcamentoMensal > 0 || d.despesasEsteMes > 0)
  .sort((a, b) => b[1].usoPercent - a[1].usoPercent);

if (categoriasOrd.length > 0) {
  categoriasOrd.forEach(([nome, d]) => {
    const icon = d.usoPercent > 1 ? '🔴' : d.usoPercent > 0.75 ? '🟡' : '🟢';
    if (d.orcamentoMensal > 0) {
      lines.push(`${icon} *${nome}*`);
      lines.push(`   ${fmtBRL(d.despesasEsteMes)} de ${fmtBRL(d.orcamentoMensal)} (${fmtPct(d.usoPercent * 100)} do orçamento mensal)`);
    } else if (d.despesasEsteMes > 0) {
      lines.push(`⚪ *${nome}*: ${fmtBRL(d.despesasEsteMes)} (sem orçamento)`);
    }
  });
}

const totalUso = data.totalOrcamento > 0 ? (data.totalDespesasMes / data.totalOrcamento) : 0;
const totalIcon = totalUso > 1 ? '🔴' : totalUso > 0.75 ? '🟡' : '🟢';

lines.push('');
lines.push(`${totalIcon} *TOTAL GERAL:*`);
lines.push(`   ${fmtBRL(data.totalDespesasMes)} de ${fmtBRL(data.totalOrcamento)} (${fmtPct(totalUso * 100)} do orçamento mensal)`);

lines.push('');
lines.push('━━━━━━━━━━━━━━━━━━━━━');
lines.push('');
lines.push('📊 *COMPARAÇÃO vs MÊS ANTERIOR*');
lines.push(`   (Acumulado até dia ${data.diaDoMes})`);
lines.push('');

const diferencaMes = data.totais.mesAtual - data.totais.mesAnteriorAteDia;
const pctDif = data.totais.mesAnteriorAteDia > 0 ? ((diferencaMes / data.totais.mesAnteriorAteDia) * 100) : 0;

lines.push(`   ${mesAtualLabel}: ${fmtBRL(data.totais.mesAtual)}`);
lines.push(`   ${mesAnteriorLabel} (até dia ${data.diaDoMes}): ${fmtBRL(data.totais.mesAnteriorAteDia)}`);
lines.push(`   ${mesAnteriorLabel} (total): ${fmtBRL(data.totais.mesAnteriorCompleto)}`);
lines.push('');

if (diferencaMes < 0) {
  lines.push(`✅ *${fmtBRL(Math.abs(diferencaMes))} abaixo do mês anterior até agora*`);
  lines.push(`   📉 ${fmtPct(Math.abs(pctDif))} menor que ${mesAnteriorLabel}`);
} else if (diferencaMes > 0) {
  lines.push(`⚠️ *${fmtBRL(diferencaMes)} acima do mês anterior até agora*`);
  lines.push(`   📈 ${fmtPct(pctDif)} maior que ${mesAnteriorLabel}`);
} else {
  lines.push(`➡️ *Mesmo valor que ${mesAnteriorLabel}*`);
}

lines.push('');
lines.push('📸 _Gráficos abaixo..._');

return [{ json: { ...data, text: lines.join('\n') } }];

const data = $('Format Weekly Summary').first().json;
const entries = Object.entries(data.por_conta || {})
  .sort((a, b) => b[1].total - a[1].total);

if (entries.length === 0) {
  return [{ json: { labels: ['Sem dados'], values: [0], backgroundColor: ['#ccc'] } }];
}

const labels = entries.map(([conta]) => conta);
const values = entries.map(([, info]) => info.total);

return [{
  json: {
    labels,
    values,
    backgroundColor: ['#4CAF50', '#2196F3', '#FF9800']
  }
}];

const data = $('Format Weekly Summary').first().json;
const entries = Object.entries(data.por_categoria || {})
  .sort((a, b) => b[1].total - a[1].total)
  .slice(0, 8);

if (entries.length === 0) {
  return [{ json: { labels: ['Sem dados'], values: [0], backgroundColor: ['#ccc'] } }];
}

const labels = entries.map(([cat]) => cat.length > 18 ? cat.substring(0, 15) + '...' : cat);
const values = entries.map(([, info]) => info.total);

return [{
  json: {
    labels,
    values,
    backgroundColor: ['#4CAF50', '#2196F3', '#FF9800', '#9C27B0', '#F44336', '#00BCD4', '#FFC107', '#795548']
  }
}];

const prop = $('Set Report Config (Monthly)').first().json.prop;
// ============================================
// PROCESS MONTHLY DATA - Relatório Estratégico
// ============================================

const monthReportRaw = $('Get Month Report').all();
const categoriasRaw = $('Get Categorias1').all();
const contasRaw = $('Get Contas1').all();
const month2Raw = $('Get Month M-2').all();
const month3Raw = $('Get Month M-3').all();
const month4Raw = $('Get Month M-4').all();

// Fuso horário São Paulo
const agora = new Date();
const hojeStr = agora.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' });
const hoje = new Date(hojeStr);

// Mês do relatório (mês anterior)
const mesRelatorio = hoje.getMonth() === 0 ? 11 : hoje.getMonth() - 1;
const anoRelatorio = hoje.getMonth() === 0 ? hoje.getFullYear() - 1 : hoje.getFullYear();

const nomesMeses = ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'];
const nomesMesesCurto = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

const getMesLabel = (offset) => {
  let m = mesRelatorio - offset;
  if (m < 0) m += 12;
  return nomesMesesCurto[m];
};

// === MAPEAR CATEGORIAS E CONTAS ===
const categoriasMap = {};
const categoriasInfo = {};
categoriasRaw.forEach(item => {
  const props = item.json?.properties || {};
  const id = item.json?.id;
  let nome = '';
  for (const [key, value] of Object.entries(props)) {
    if (value.type === 'title' && value.title?.length > 0) {
      nome = value.title[0]?.plain_text || '';
      break;
    }
  }
  const orcamento = props[prop.orcamento]?.number ?? 0;
  if (id && nome) {
    categoriasMap[id] = nome;
    categoriasInfo[nome] = { orcamento };
  }
});

const contasMap = {};
contasRaw.forEach(item => {
  const props = item.json?.properties || {};
  const id = item.json?.id;
  let nome = '';
  for (const [key, value] of Object.entries(props)) {
    if (value.type === 'title' && value.title?.length > 0) {
      nome = value.title[0]?.plain_text || '';
      break;
    }
  }
  if (id && nome) contasMap[id] = nome;
});

// Função para processar despesas
const processExpenses = (raw, comDetalhes = false) => {
  return raw.map(item => {
    const p = item.json?.properties ?? {};
    const catRelation = p[prop.categoria]?.relation || [];
    const categoriaId = catRelation[0]?.id || null;
    const categoria = categoriaId ? (categoriasMap[categoriaId] || 'Sem categoria') : 'Sem categoria';
    const contaRelation = p['Conta']?.relation || [];
    const contaId = contaRelation[0]?.id || null;
    const conta = contaId ? (contasMap[contaId] || 'Sem conta') : 'Sem conta';

    const base = {
      data: p['Data']?.date?.start ?? null,
      valor: p['Valor']?.number ?? 0,
      categoria,
      conta
    };

    if (comDetalhes) {
      base.despesa = p[prop.title]?.title?.[0]?.text?.content ?? p[prop.title]?.title?.[0]?.plain_text ?? 'Sem título';
      base.formaPagamento = (() => { const rel = p[prop.forma_pagamento]?.relation || []; const fpId = rel[0]?.id; return fpId || 'N/A'; })();
    }
    return base;
  }).filter(e => e.data);
};

// === PROCESSAR MÊS DO RELATÓRIO ===
const expensesMesReport = processExpenses(monthReportRaw, true);
const expensesMes2 = processExpenses(month2Raw);
const expensesMes3 = processExpenses(month3Raw);
const expensesMes4 = processExpenses(month4Raw);

// === MÉTRICAS DO MÊS ===
const totalMes = expensesMesReport.reduce((sum, e) => sum + e.valor, 0);
const qtdTransacoes = expensesMesReport.length;
const diasNoMes = new Date(anoRelatorio, mesRelatorio + 1, 0).getDate();
const mediaDiaria = qtdTransacoes > 0 ? totalMes / diasNoMes : 0;
const mediaTransacao = qtdTransacoes > 0 ? totalMes / qtdTransacoes : 0;

// Totais meses anteriores
const totalMes2 = expensesMes2.reduce((sum, e) => sum + e.valor, 0);
const totalMes3 = expensesMes3.reduce((sum, e) => sum + e.valor, 0);
const totalMes4 = expensesMes4.reduce((sum, e) => sum + e.valor, 0);

// Média dos últimos 3 meses (excluindo o mês do relatório)
const mediaMeses = (totalMes2 + totalMes3 + totalMes4) / 3;

// Variação vs mês anterior
const variacaoVsMesAnterior = totalMes2 > 0 ? ((totalMes - totalMes2) / totalMes2 * 100) : 0;

// === POR CATEGORIA (mês do relatório) ===
const porCategoria = {};
expensesMesReport.forEach(e => {
  if (!porCategoria[e.categoria]) porCategoria[e.categoria] = { total: 0, count: 0 };
  porCategoria[e.categoria].total += e.valor;
  porCategoria[e.categoria].count++;
});

// Análise de orçamento por categoria
const analiseOrcamento = [];
let totalOrcamento = 0;
Object.entries(categoriasInfo).forEach(([nome, info]) => {
  const gasto = porCategoria[nome]?.total || 0;
  const orcamento = info.orcamento;
  totalOrcamento += orcamento;
  const uso = orcamento > 0 ? (gasto / orcamento) : (gasto > 0 ? 999 : 0);
  const diferenca = orcamento - gasto;
  analiseOrcamento.push({ nome, gasto, orcamento, uso, diferenca, count: porCategoria[nome]?.count || 0 });
});
analiseOrcamento.sort((a, b) => b.uso - a.uso);

// === POR CONTA ===
const porConta = {};
expensesMesReport.forEach(e => {
  if (!porConta[e.conta]) porConta[e.conta] = { total: 0, count: 0 };
  porConta[e.conta].total += e.valor;
  porConta[e.conta].count++;
});

// === POR FORMA DE PAGAMENTO ===
const porPagamento = {};
expensesMesReport.forEach(e => {
  if (!porPagamento[e.formaPagamento]) porPagamento[e.formaPagamento] = { total: 0, count: 0 };
  porPagamento[e.formaPagamento].total += e.valor;
  porPagamento[e.formaPagamento].count++;
});

// === TOP 5 MAIORES DESPESAS ===
const top5Despesas = [...expensesMesReport]
  .sort((a, b) => b.valor - a.valor)
  .slice(0, 5);

// === EVOLUÇÃO MENSAL POR CATEGORIA (4 meses) ===
const evolucaoCategoria = {};
[expensesMesReport, expensesMes2, expensesMes3, expensesMes4].forEach((expenses, idx) => {
  expenses.forEach(e => {
    if (!evolucaoCategoria[e.categoria]) evolucaoCategoria[e.categoria] = [0, 0, 0, 0];
    evolucaoCategoria[e.categoria][idx] += e.valor;
  });
});

// === DADOS PARA GRÁFICOS ===
const mesesLabels = [getMesLabel(0), getMesLabel(1), getMesLabel(2), getMesLabel(3)];
const totaisMeses = [totalMes, totalMes2, totalMes3, totalMes4];

// Uso do orçamento total
const usoOrcamentoTotal = totalOrcamento > 0 ? (totalMes / totalOrcamento) : 0;

return [{
  json: {
    mesRelatorio: nomesMeses[mesRelatorio],
    anoRelatorio,
    mesRelatorioCurto: nomesMesesCurto[mesRelatorio],
    metricas: {
      totalMes,
      qtdTransacoes,
      diasNoMes,
      mediaDiaria,
      mediaTransacao,
      mediaMeses,
      variacaoVsMesAnterior
    },
    orcamento: {
      total: totalOrcamento,
      gasto: totalMes,
      uso: usoOrcamentoTotal,
      diferenca: totalOrcamento - totalMes
    },
    analiseOrcamento,
    porCategoria,
    porConta,
    porPagamento,
    top5Despesas,
    evolucao: {
      mesesLabels,
      totaisMeses,
      porCategoria: evolucaoCategoria
    }
  }
}];

// ============================================
// FORMAT MONTHLY SUMMARY - Relatório Estratégico
