const fmtPct = (n) => `${Number(n || 0).toFixed(0)}%`;
const fmtPctSinal = (n) => n >= 0 ? `+${fmtPct(n)}` : fmtPct(n);

const lines = [
  '🏺 *' + _brand + '* 🏺',
  '',
  '📅 *RELATÓRIO MENSAL*',
