(() => {
const query = $json.output || {};
const filters = query.filters || {};
const prop = $('Resolve Tenant Config').first().json.prop;

const opts = $items("Format Dynamic Options")[0].json;
const categoriasMap = opts.categorias_map;
const contasMap = opts.contas_map;
const formasPagamentoMap = opts.formas_pagamento_map;

const conditions = [];

if (query.date_start && query.date_end) {
  conditions.push({ "property": "Data", "date": { "on_or_after": query.date_start } });
  conditions.push({ "property": "Data", "date": { "on_or_before": query.date_end } });
} else if (query.date_start) {
  conditions.push({ "property": "Data", "date": { "on_or_after": query.date_start } });
} else if (query.date_end) {
  conditions.push({ "property": "Data", "date": { "on_or_before": query.date_end } });
}

const asArray = (v) => Array.isArray(v) ? v : [v];
const relationCond = (property, pageId) => ({ property, relation: { contains: pageId } });
const relationOrBlock = (property, names, mapObj) => {
  const ids = asArray(names).map((n) => mapObj[n]).filter(Boolean);
  if (ids.length === 0) return null;
  return ids.length === 1 ? relationCond(property, ids[0]) : { or: ids.map((id) => relationCond(property, id)) };
};

if (filters.payment_method && formasPagamentoMap) {
  const pmFilter = relationOrBlock(prop.forma_pagamento, filters.payment_method, formasPagamentoMap);
  if (pmFilter) conditions.push(pmFilter);
}
if (filters.categoria) {
  const catFilter = relationOrBlock(prop.categoria, filters.categoria, categoriasMap);
  if (catFilter) conditions.push(catFilter);
}
if (filters.conta) {
  const contaFilter = relationOrBlock("Conta", filters.conta, contasMap);
  if (contaFilter) conditions.push(contaFilter);
}

let notionFilterString = "";
if (conditions.length > 0) {
  const filterObj = conditions.length === 1 ? conditions[0] : { "and": conditions };
  notionFilterString = JSON.stringify(filterObj);
}

const conditions_parcelas = [];
if (query.date_start && query.date_end) { conditions_parcelas.push({ property: "Data Cobranca", date: { on_or_after: query.date_start } }); conditions_parcelas.push({ property: "Data Cobranca", date: { on_or_before: query.date_end } }); } else if (query.date_start) { conditions_parcelas.push({ property: "Data Cobranca", date: { on_or_after: query.date_start } }); } else if (query.date_end) { conditions_parcelas.push({ property: "Data Cobranca", date: { on_or_before: query.date_end } }); }
let notionFilterStringParcelas = "";
if (conditions_parcelas.length > 0) { const filterObjP = conditions_parcelas.length === 1 ? conditions_parcelas[0] : { and: conditions_parcelas }; notionFilterStringParcelas = JSON.stringify(filterObjP); }
return {
  notion_filter_string: notionFilterString,
  has_filter: notionFilterString !== "",
  data_source: query.data_source || "transacoes",
  notion_filter_string_parcelas: notionFilterStringParcelas,
  has_filter_parcelas: notionFilterStringParcelas !== "",
  query_params: query
};
})()
}}

