// Consolidates input from Text, Voice, Photo or Document into a single 'text' property
const type = $('Direciona Tipo Msg').item.json.message_type;
let text = '';

if (type === 'text') {
  text = $('Normaliza mensagem').item.json.text;
} else if (type === 'photo') {
  text = $('Normaliza mensagem1').item.json.text;
} else if (type === 'voice') {
  text = $('Normaliza mensagem2').item.json.text;
} else if (type === 'document') {
  text = $('Normaliza mensagem3').item.json.text;
}

return { text };

// Função para conversão de data local da mensagem (São Paulo) -> YYYY-MM-DD
function formatLocalDateFromUnix(unixSeconds, timeZone = 'America/Sao_Paulo') {
  if (!unixSeconds) return '';

  const date = new Date(unixSeconds * 1000);

  const br = date.toLocaleDateString('pt-BR', {
    timeZone,
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
  });

  const [dia, mes, ano] = br.split('/');
  return `${ano}-${mes}-${dia}`;
}

// Extração das mensagens
const msg   = $('Resolve Tenant Config').first().json.message ?? {};
const reply = msg.reply_to_message ?? {};

// Dados do áudio transcrito
const user_text = ($json.text ?? '').toString().trim();

// Função para pegar texto e/ou caption
const pickText = (m) => (m?.text ?? m?.caption ?? '').toString().trim();
const pickCaption = (m) => (m?.caption ?? '').toString().trim();

// ------------------------------------------
// Dados do reply (se existir)
// ------------------------------------------
const reply_from = [
  reply?.from?.first_name,
  reply?.from?.last_name,
].filter(Boolean).join(' ')
   || reply?.from?.username
   || '';

const reply_date = reply?.date
  ? formatLocalDateFromUnix(reply.date)
  : '';

const reply_text = pickText(reply);
const reply_caption = pickCaption(reply);

// ------------------------------------------
// Dados da mensagem do usuário
// ------------------------------------------
const user_from = [
  msg?.from?.first_name,
  msg?.from?.last_name,
].filter(Boolean).join(' ')
   || msg?.from?.username
   || '';

const user_date = msg?.date
  ? formatLocalDateFromUnix(msg.date)
  : '';
const user_caption = pickCaption(msg);

// ------------------------------------------
// Montagem final do texto
// ------------------------------------------
let finalMessage;

if (reply_text) {
  finalMessage = 
`Mensagem Anterior:
De: ${reply_from}
Data: ${reply_date}
Texto: ${reply_text}`;

  if (reply_caption) {
    finalMessage += `

Comentario adicional: ${reply_caption}`;
  }

  finalMessage += `

Mensagem User:
De: ${user_from}
Data: ${user_date}
Imagem transcrita: ${user_text}`;

  if (user_caption) {
    finalMessage += `
Comentario adicional User: ${user_caption}`;
  }

} else {
  finalMessage = 
`Mensagem User:
De: ${user_from}
Data: ${user_date}
Imagem transcrita: ${user_text}`;

  if (user_caption) {
    finalMessage += `
Comentario adicional User: ${user_caption}`;
  }
}

// Ao invés de retornar só a string, retornamos um objeto com a prop "text"
return {
  text: finalMessage,
}

