const prop = $('Resolve Tenant Config').first().json.prop;
// ============================================================================
// NODE: Aggregate Parcelas
// DB: Despesas - Parcelas (rollups: Conta, Categoria Despesa, Forma de Pagamento, ID_transacao)
// ============================================================================

const queryParams = $('Build Notion Filter').first().json.query_params;
const aggregation = queryParams.aggregation || 'sum';
const groupBy = queryParams.group_by;
const dateGranularity = queryParams.date_granularity;
const filters = queryParams.filters || {};

// Mapas a partir do Format Dynamic Options (nome -> id)
const opts = $('Format Dynamic Options').first().json;
const categoriasMap = opts.categorias_map || {};
const contasMap = opts.contas_map || {};
const formasPagamentoMap = opts.formas_pagamento_map || {};

const categoriasIdToName = Object.entries(categoriasMap).reduce((acc, [name, id]) => { acc[id] = name; return acc; }, {});
const contasIdToName = Object.entries(contasMap).reduce((acc, [name, id]) => { acc[id] = name; return acc; }, {});
const formasPagamentoIdToName = Object.entries(formasPagamentoMap).reduce((acc, [name, id]) => { acc[id] = name; return acc; }, {});

// Extrai primeiro ID de um rollup do tipo relation (Notion: rollup.results[].relation ou .array[])
function getFirstRelationId(prop) {
  if (!prop || prop.type !== 'rollup' || !prop.rollup) return null;
  const r = prop.rollup;
  const arr = r.results || r.array || [];
  const first = arr[0];
  if (!first) return null;
  if (first.id) return first.id;
  const rel = first.relation;
  if (Array.isArray(rel) && rel[0]) return rel[0].id || null;
  if (rel && typeof rel === 'object' && rel.id) return rel.id;
  return null;
}

// Extrai número do rollup ID_transacao (number ou unique_id)
function getIdTransacaoNumero(prop) {
  if (!prop || prop.type !== 'rollup' || !prop.rollup) return null;
  const r = prop.rollup;
  if (typeof r.number === 'number' && isFinite(r.number)) return r.number;
  if (r.unique_id && typeof r.unique_id.number === 'number') return r.unique_id.number;
  const arr = r.results || r.array || [];
  const first = arr[0];
  if (first && (first.unique_id?.number != null)) return first.unique_id.number;
  if (first && (first.number != null)) return first.number;
  return null;
}

function pickTitle(titleArr) {
  if (Array.isArray(titleArr) && titleArr.length > 0) {
    const s = titleArr.map(t => (t?.plain_text ?? t?.text?.content ?? '')).join('').trim();
    return s || 'N/A';
  }
  return 'N/A';
}

function getNumber(n) {
  return (typeof n === 'number' && isFinite(n)) ? n : 0;
}

// Normalização: uma parcela = mesmo formato de expense (para reuso do formatter)
const parcelas = items.map(item => {
  const p = item.json?.properties ?? {};

  const valor = getNumber(p['Valor']?.number);
  const data = p['Data Cobranca']?.date?.start ?? 'N/A';
  const despesa = pickTitle(p[prop.title]?.title ?? []);

  const contaId = getFirstRelationId(p['Conta']);
  const categoriaId = getFirstRelationId(p[prop.categoria]);
  const formaPagamentoId = getFirstRelationId(p[prop.forma_pagamento]);
  const idTransNum = getIdTransacaoNumero(p['ID_transacao']);

  const conta = contaId ? (contasIdToName[contaId] || 'Sem conta') : 'Sem conta';
  const categoria = categoriaId ? (categoriasIdToName[categoriaId] || 'Sem categoria') : 'Sem categoria';
  const payment_method = formaPagamentoId ? (formasPagamentoIdToName[formaPagamentoId] || 'Sem forma de pagamento') : 'Sem forma de pagamento';

  return {
    id_transacao: idTransNum ?? 'N/A',
    despesa,
    valor,
    data,
    conta,
    conta_id: contaId,
    categoria,
    categoria_id: categoriaId,
    payment_method,
    payment_method_id: formaPagamentoId
  };
});

// Estrutura de resultado igual ao Aggregate Results (periodo, tipo_agregacao, group_by, quantidade, total_geral, despesas, etc.)
let result = {
  periodo: `${queryParams.date_start || ''} até ${queryParams.date_end || ''}`,
  filtros_aplicados: filters,
  tipo_agregacao: aggregation,
  group_by: groupBy
};

function formatDateKey(dateStr, granularity) {
  if (!dateStr || dateStr === 'N/A') return 'Sem Data';
  const date = new Date(dateStr + 'T00:00:00');
  if (isNaN(date.getTime())) return 'Data Inválida';
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  switch (granularity) {
    case 'day': return `${year}-${month}-${day}`;
    case 'week':
      const startOfYear = new Date(year, 0, 1);
      const dayOfYear = Math.floor((date - startOfYear) / (24 * 60 * 60 * 1000));
      const weekNum = Math.ceil((dayOfYear + startOfYear.getDay() + 1) / 7);
      return `${year}-W${String(weekNum).padStart(2, '0')}`;
    case 'month': return `${year}-${month}`;
    case 'year': return `${year}`;
    default: return dateStr;
  }
}

function formatDateDisplay(key, granularity) {
  if (key === 'Sem Data' || key === 'Data Inválida') return key;
  const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
  switch (granularity) {
    case 'day': const [y, m, d] = key.split('-'); return `${d}/${m}/${y}`;
    case 'week': const [year, week] = key.split('-W'); return `Semana ${week}/${year}`;
    case 'month': const [year2, month] = key.split('-'); return `${months[parseInt(month) - 1]}/${year2}`;
    case 'year': return key;
    default: return key;
  }
}

result.quantidade = parcelas.length;

if (groupBy === 'date' && dateGranularity) {
  const grouped = {};
  parcelas.forEach(exp => {
    const key = formatDateKey(exp.data, dateGranularity);
    if (!grouped[key]) grouped[key] = { expenses: [], total: 0, count: 0 };
    grouped[key].expenses.push(exp);
    grouped[key].total += exp.valor;
    grouped[key].count++;
  });
  const sortedKeys = Object.keys(grouped).sort();
  result.is_time_series = true;
  result.date_granularity = dateGranularity;
  result.time_series = sortedKeys.map(key => {
    const period = grouped[key];
    let value = aggregation === 'sum' ? period.total : aggregation === 'average' ? (period.count ? period.total / period.count : 0) : aggregation === 'count' ? period.count : period.total;
    if (aggregation === 'max' && period.expenses.length) value = Math.max(...period.expenses.map(e => e.valor));
    if (aggregation === 'min' && period.expenses.length) value = Math.min(...period.expenses.filter(e => e.valor > 0).map(e => e.valor) || [0]);
    return { period: key, period_display: formatDateDisplay(key, dateGranularity), value: parseFloat(Number(value).toFixed(2)), total: period.total, count: period.count };
  });
  const grandTotal = result.time_series.reduce((sum, t) => sum + t.total, 0);
  result.series_summary = { periods_count: result.time_series.length, total_geral: grandTotal };
} else if (aggregation === 'sum') {
  result.total_geral = parcelas.reduce((s, e) => s + e.valor, 0);
  if (groupBy === 'categoria') {
    const g = {}; parcelas.forEach(exp => { const k = exp.categoria || 'Sem categoria'; g[k] = (g[k] || 0) + exp.valor; });
    result.grouped_totals = g; result.grand_total = result.total_geral;
  } else if (groupBy === 'conta') {
    const g = {}; parcelas.forEach(exp => { const k = exp.conta || 'Sem conta'; g[k] = (g[k] || 0) + exp.valor; });
    result.grouped_totals = g; result.grand_total = result.total_geral;
  } else if (groupBy === 'payment_method') {
    const g = {}; parcelas.forEach(exp => { const k = exp.payment_method || 'Outros'; g[k] = (g[k] || 0) + exp.valor; });
    result.grouped_totals = g; result.grand_total = result.total_geral;
  }
} else if (aggregation === 'average') {
  result.media = parcelas.length ? (parcelas.reduce((s, e) => s + e.valor, 0) / parcelas.length).toFixed(2) : '0.00';
} else if (aggregation === 'count') {
  if (groupBy && groupBy !== 'date') {
    const g = {};
    parcelas.forEach(exp => {
      const key = groupBy === 'categoria' ? (exp.categoria || 'Sem categoria') : groupBy === 'conta' ? (exp.conta || 'Sem conta') : groupBy === 'payment_method' ? (exp.payment_method || 'Outros') : 'Outros';
      g[key] = (g[key] || 0) + 1;
    });
    result.grouped_counts = g;
  }
} else if (aggregation === 'max') {
  result.maior_despesa = parcelas.length ? parcelas.reduce((max, e) => e.valor > max.valor ? e : max, parcelas[0]) : { id_transacao: 'N/A', despesa: 'N/A', valor: 0, data: 'N/A', conta: 'Sem conta', categoria: 'Sem categoria', payment_method: 'N/A' };
} else if (aggregation === 'min') {
  const valid = parcelas.filter(e => e.valor > 0);
  result.menor_despesa = valid.length ? valid.reduce((min, e) => e.valor < min.valor ? e : min, valid[0]) : { id_transacao: 'N/A', despesa: 'N/A', valor: 0, data: 'N/A', conta: 'Sem conta', categoria: 'Sem categoria', payment_method: 'N/A' };
} else if (aggregation === 'list') {
  result.despesas = parcelas.slice(0, 50);
  result.total_encontradas = parcelas.length;
} else if (aggregation === 'consolidado') {
  const total = parcelas.reduce((s, e) => s + e.valor, 0);
  result.total_geral = total;
  result.media = parcelas.length ? (total / parcelas.length).toFixed(2) : '0.00';
  const valid = parcelas.filter(e => e.valor > 0);
  if (valid.length) {
    const max = Math.max(...valid.map(e => e.valor));
    const min = Math.min(...valid.map(e => e.valor));
    result.maior_despesa = valid.find(e => e.valor === max);
    result.menor_despesa = valid.find(e => e.valor === min);
  } else {
    result.maior_despesa = { id_transacao: 'N/A', despesa: 'N/A', valor: 0, data: 'N/A', conta: 'Sem conta', categoria: 'Sem categoria', payment_method: 'N/A' };
    result.menor_despesa = result.maior_despesa;
  }
  result.despesas = parcelas.slice(0, 10);
  result.total_encontradas = parcelas.length;
}

return [{ json: result }];

// Format Parcelas Response - mesmo padrão do Formata Resposta para Telegram (conta, categoria, payment_method, id_transacao)
const _brand = $('Resolve Tenant Config').first().json.brand_name;
const payload = Array.isArray(items) && items.length > 0 ? (items[0].json ?? items[0]) : (items[0] ?? {});
const p = payload;

const escapeHtml = (v) => String(v ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const safe = (v, alt = 'N/A') => (v === null || v === undefined || v === '') ? alt : escapeHtml(v);
const fmtBRL = (n) => 'R$ ' + (Number(n) || 0).toFixed(2).replace('.', ',');

function renderExpense(exp, index) {
  const lines = [];
  const nome = safe(exp.despesa);
  if (index != null) lines.push(`${index}. <b>${nome}</b>`);
  else lines.push(`<b>${nome}</b>`);
  lines.push(`   📅 ${safe(exp.data)}`);
  lines.push(`   💰 ${fmtBRL(exp.valor)}`);
  if (exp.categoria && exp.categoria !== 'Sem categoria') lines.push(`   🗃️ ${safe(exp.categoria)}`);
  if (exp.conta && exp.conta !== 'Sem conta') lines.push(`   🏦 ${safe(exp.conta)}`);
  lines.push(`   💳 ${safe(exp.payment_method)}`);
  lines.push(`   🆔 ID: ${safe(exp.id_transacao)}`);
  return lines.join('\n');
}

const header = [
  '🏺 <b>' + _brand + '</b> 🏺',
  '',
  '📊 <b>Consulta: Parcelas (fluxo de caixa)</b>',
  `📅 <b>Período:</b> ${safe(p.periodo)}`,
  '━━━━━━━━━━━━━━━━━━'
];
if (p.filtros_aplicados && Object.keys(p.filtros_aplicados).length) {
  const f = p.filtros_aplicados;
  const parts = [];
  if (f.conta != null) parts.push(`Conta: ${safe(f.conta)}`);
  if (f.categoria != null) parts.push(`Categoria: ${safe(f.categoria)}`);
  if (f.payment_method != null) parts.push(`Forma: ${safe(f.payment_method)}`);
  if (parts.length) header.push('🔍 ' + parts.join(' | '));
}
const body = [];

if (p.is_time_series && Array.isArray(p.time_series)) {
  body.push('', '📊 <b>Série temporal</b>', '━━━━━━━━━━━━━━━━━━');
  p.time_series.forEach(period => {
    body.push(`📆 ${safe(period.period_display)}: ${fmtBRL(period.value)} (${safe(period.count)} itens)`);
  });
  if (p.series_summary) body.push('', `📈 Total: ${fmtBRL(p.series_summary.total_geral)}`);
  body.push('', `🔢 Parcelas: ${safe(p.quantidade, 0)}`);
} else if (p.tipo_agregacao === 'consolidado' || p.tipo_agregacao === 'sum') {
  if (p.grouped_totals) {
    const label = p.group_by === 'categoria' ? 'Categoria' : p.group_by === 'conta' ? 'Conta' : p.group_by === 'payment_method' ? 'Forma' : safe(p.group_by);
    body.push('', `📊 Totais por ${label}:`, '━━━━━━━━━━━━━━━━━━');
    Object.entries(p.grouped_totals).sort((a, b) => b[1] - a[1]).forEach(([k, v]) => body.push(`   • ${safe(k)}: ${fmtBRL(v)}`));
    if (p.grand_total != null) body.push('━━━━━━━━━━━━━━━━━━', `   💰 TOTAL: ${fmtBRL(p.grand_total)}`);
  } else if (p.total_geral != null) body.push('', `💰 Total: ${fmtBRL(p.total_geral)}`);
  if (p.quantidade != null) body.push(`🔢 Parcelas: ${safe(p.quantidade)}`);
  if (p.media != null) body.push(`📈 Média: ${fmtBRL(p.media)}`);
  if (p.maior_despesa) { body.push('', '⬆️ Maior:', renderExpense(p.maior_despesa)); }
  if (p.menor_despesa) { body.push('', '⬇️ Menor:', renderExpense(p.menor_despesa)); }
  if (Array.isArray(p.despesas) && p.despesas.length) {
    body.push('', '📋 Parcelas:', '━━━━━━━━━━━━━━━━━━');
    p.despesas.forEach((exp, i) => { body.push(renderExpense(exp, i + 1), ''); });
  }
} else if (p.tipo_agregacao === 'list') {
  const arr = Array.isArray(p.despesas) ? p.despesas : [];
  body.push('', `📋 Parcelas (${safe(p.total_encontradas ?? arr.length)}):`, '━━━━━━━━━━━━━━━━━━');
  arr.forEach((exp, i) => { body.push(renderExpense(exp, i + 1), ''); });
  if ((p.total_encontradas || 0) > arr.length) body.push(`... e mais ${p.total_encontradas - arr.length}`);
} else if (p.tipo_agregacao === 'max' && p.maior_despesa) {
  body.push('', '⬆️ Maior parcela:', renderExpense(p.maior_despesa));
} else if (p.tipo_agregacao === 'min' && p.menor_despesa) {
  body.push('', '⬇️ Menor parcela:', renderExpense(p.menor_despesa));
} else if (p.tipo_agregacao === 'average') {
  body.push('', `📈 Média: ${fmtBRL(p.media)}`, `🔢 Parcelas: ${safe(p.quantidade, 0)}`);
} else if (p.tipo_agregacao === 'count') {
  if (p.grouped_counts) {
    const label = p.group_by === 'categoria' ? 'Categoria' : p.group_by === 'conta' ? 'Conta' : p.group_by === 'payment_method' ? 'Forma' : safe(p.group_by);
    body.push('', `📊 Contagem por ${label}:`, '━━━━━━━━━━━━━━━━━━');
    Object.entries(p.grouped_counts).sort((a, b) => b[1] - a[1]).forEach(([k, c]) => body.push(`   • ${safe(k)}: ${c}`));
  }
  body.push('', `🔢 Total parcelas: ${safe(p.quantidade, 0)}`);
}

const text = [...header, ...body].join('\n');
return [{ json: { text } }];

