function formatLocalDateFromUnix(unixSeconds, timeZone) {
  timeZone = timeZone || 'America/Sao_Paulo';
  if (!unixSeconds) return '';
  const date = new Date(unixSeconds * 1000);
  const br = date.toLocaleDateString('pt-BR', { timeZone, day: '2-digit', month: '2-digit', year: 'numeric' });
  const [dia, mes, ano] = br.split('/');
  return `${ano}-${mes}-${dia}`;
}
