];

// Variação vs mês anterior
const iconVar = m.variacaoVsMesAnterior < 0 ? '📉' : m.variacaoVsMesAnterior > 0 ? '📈' : '➡️';
const txtVar = m.variacaoVsMesAnterior < 0 ? 'menos' : 'mais';
lines.push(`${iconVar} *${fmtPctSinal(m.variacaoVsMesAnterior)}* vs mês anterior`);
lines.push(`📊 *Média 3 meses anteriores:* ${fmtBRL(m.mediaMeses)}`);

// === DISTRIBUIÇÃO POR CONTA ===
lines.push('');
lines.push('━━━━━━━━━━━━━━━━━━━━━━');
